const base = $('Normalize Submission').first().json;
const pdfText = $input.first().json.text || '';
const languageLabel = base.feedbackLanguage === 'fr' || base.evaluationLanguage === 'fr' ? 'French' : (base.feedbackLanguage || base.evaluationLanguage || 'French');
const feedbackInstructions =
  base.feedbackInstructions ||
  'Return all student-facing evaluation text in French. Use simple, clear, helpful French for a student.';
const prompt = `You are an academic evaluator for a university homework platform. Analyze the homework below and return only valid JSON.\n\nEvaluation rules:\n- score, grammar_score, structure_score, content_score: numbers from 0 to 20\n- ai_probability: number from 0 to 100\n- feedback: short but useful feedback for a student, written in ${languageLabel}\n- key_strengths: array of 2 to 4 short points, written in ${languageLabel}\n- improvement_tips: array of 2 to 4 short actionable tips, written in ${languageLabel}\n- missing_questions: when used, write each note in ${languageLabel}\n- recommended_teacher_action: one of ["approve", "review", "investigate"]\n\nLanguage rules:\n- ${feedbackInstructions}\n- Do not write feedback, strengths, tips, or missing question notes in English. Keep only the JSON keys and enum values in English.\n\nContext:\nTitle: ${base.title}\nSubject: ${base.subject}\nStudent: ${base.studentName}\nClass: ${base.className}\nSubmission type: PDF\n\nTexte du devoir :\n${pdfText}`;

return [
  {
    json: {
      ...base,
      extractedText: pdfText,
      geminiRequestBody: {
        contents: [
          {
            parts: [
              {
                text: prompt
              }
            ]
          }
        ],
        generationConfig: {
          responseMimeType: 'application/json',
          responseJsonSchema: {
            type: 'object',
            properties: {
              score: { type: 'number', minimum: 0, maximum: 20, description: 'Global score over 20.' },
              feedback: { type: 'string', description: 'Clear student feedback in French in 2 to 5 sentences.' },
              grammar_score: { type: 'number', minimum: 0, maximum: 20 },
              structure_score: { type: 'number', minimum: 0, maximum: 20 },
              content_score: { type: 'number', minimum: 0, maximum: 20 },
              ai_probability: { type: 'number', minimum: 0, maximum: 100 },
              key_strengths: { type: 'array', items: { type: 'string', description: 'French text.' }, minItems: 2, maxItems: 4 },
              improvement_tips: { type: 'array', items: { type: 'string', description: 'French text.' }, minItems: 2, maxItems: 4 },
              recommended_teacher_action: {
                type: 'string',
                enum: ['approve', 'review', 'investigate']
              }
            },
            required: [
              'score',
              'feedback',
              'grammar_score',
              'structure_score',
              'content_score',
              'ai_probability',
              'key_strengths',
              'improvement_tips',
              'recommended_teacher_action'
            ]
          }
        }
      }
    }
  }
];

const base = $input.first().json;
const languageLabel = base.feedbackLanguage === 'fr' || base.evaluationLanguage === 'fr' ? 'French' : (base.feedbackLanguage || base.evaluationLanguage || 'French');
const feedbackInstructions =
  base.feedbackInstructions ||
  'Return all student-facing evaluation text in French. Use simple, clear, helpful French for a student.';
const prompt = `You are an academic evaluator for a university homework platform. Analyze the homework below and return only valid JSON.\n\nEvaluation rules:\n- score, grammar_score, structure_score, content_score: numbers from 0 to 20\n- ai_probability: number from 0 to 100\n- feedback: short but useful feedback for a student, written in ${languageLabel}\n- key_strengths: array of 2 to 4 short points, written in ${languageLabel}\n- improvement_tips: array of 2 to 4 short actionable tips, written in ${languageLabel}\n- missing_questions: when used, write each note in ${languageLabel}\n- recommended_teacher_action: one of ["approve", "review", "investigate"]\n\nLanguage rules:\n- ${feedbackInstructions}\n- Do not write feedback, strengths, tips, or missing question notes in English. Keep only the JSON keys and enum values in English.\n\nContext:\nTitle: ${base.title}\nSubject: ${base.subject}\nStudent: ${base.studentName}\nClass: ${base.className}\nSubmission type: Text\n\nTexte du devoir :\n${base.content}`;

return [
  {
    json: {
      ...base,
      extractedText: base.content,
      geminiRequestBody: {
        contents: [
          {
            parts: [
              {
                text: prompt
              }
            ]
          }
        ],
        generationConfig: {
          responseMimeType: 'application/json',
          responseJsonSchema: {
            type: 'object',
            properties: {
              score: { type: 'number', minimum: 0, maximum: 20, description: 'Global score over 20.' },
              feedback: { type: 'string', description: 'Clear student feedback in French in 2 to 5 sentences.' },
              grammar_score: { type: 'number', minimum: 0, maximum: 20 },
              structure_score: { type: 'number', minimum: 0, maximum: 20 },
              content_score: { type: 'number', minimum: 0, maximum: 20 },
              ai_probability: { type: 'number', minimum: 0, maximum: 100 },
              key_strengths: { type: 'array', items: { type: 'string', description: 'French text.' }, minItems: 2, maxItems: 4 },
              improvement_tips: { type: 'array', items: { type: 'string', description: 'French text.' }, minItems: 2, maxItems: 4 },
              recommended_teacher_action: {
                type: 'string',
                enum: ['approve', 'review', 'investigate']
              }
            },
            required: [
              'score',
              'feedback',
              'grammar_score',
              'structure_score',
              'content_score',
              'ai_probability',
              'key_strengths',
              'improvement_tips',
              'recommended_teacher_action'
            ]
          }
        }
      }
    }
  }
];

const raw = $json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
const parsed = JSON.parse(String(raw).trim());
const source = $('Prepare Gemini Input From PDF').all().length
  ? $('Prepare Gemini Input From PDF').first().json
  : $('Prepare Gemini Input From Text').first().json;

return [
  {
    json: {
      ...source,
      analysis: parsed
    }
  }
];

const item = $input.first().json;
const analysis = item.analysis || {};
const plagiarism = Number(item.plagiarismPercentage || 0);
const aiProbability = Number(analysis.ai_probability || 0);
const cheatingFlag = aiProbability >= 70 || plagiarism >= 60;
const strengths = Array.isArray(analysis.key_strengths) ? analysis.key_strengths : [];
const tips = Array.isArray(analysis.improvement_tips) ? analysis.improvement_tips : [];

return [
  {
    json: {
      submission_id: item.submissionId,
      score: Number(analysis.score || 0),
      feedback: analysis.feedback || '',
      grammar_score: Number(analysis.grammar_score || 0),
      structure_score: Number(analysis.structure_score || 0),
      content_score: Number(analysis.content_score || 0),
      ai_probability: aiProbability,
      plagiarism_percentage: plagiarism,
      cheating_flag: cheatingFlag,
      title: item.title,
      subject: item.subject,
      studentName: item.studentName,
      studentEmail: item.studentEmail,
      teacherEmail: item.teacherEmail,
      key_strengths: strengths,
      improvement_tips: tips,
      recommended_teacher_action: analysis.recommended_teacher_action || 'review',
      resultSubject: `Resultat du devoir - ${item.title}`,
      resultText: `Bonjour ${item.studentName},\n\nVotre devoir \"${item.title}\" a ete analyse.\n\nNote : ${Number(analysis.score || 0)} / 20\nGrammaire : ${Number(analysis.grammar_score || 0)} / 20\nStructure : ${Number(analysis.structure_score || 0)} / 20\nContenu : ${Number(analysis.content_score || 0)} / 20\nProbabilite IA : ${aiProbability}%\nPourcentage de plagiat : ${plagiarism}%\n\nFeedback :\n${analysis.feedback || ''}\n\nPoints forts :\n- ${strengths.join('\n- ')}\n\nConseils d amelioration :\n- ${tips.join('\n- ')}`,
      resultHtml: `<p>Bonjour <strong>${item.studentName}</strong>,</p><p>Votre devoir <strong>${item.title}</strong> a ete analyse.</p><p><strong>Note :</strong> ${Number(analysis.score || 0)} / 20<br><strong>Grammaire :</strong> ${Number(analysis.grammar_score || 0)} / 20<br><strong>Structure :</strong> ${Number(analysis.structure_score || 0)} / 20<br><strong>Contenu :</strong> ${Number(analysis.content_score || 0)} / 20<br><strong>Probabilite IA :</strong> ${aiProbability}%<br><strong>Pourcentage de plagiat :</strong> ${plagiarism}%</p><p><strong>Feedback :</strong><br>${analysis.feedback || ''}</p><p><strong>Points forts :</strong></p><ul>${strengths.map((item) => `<li>${item}</li>`).join('')}</ul><p><strong>Conseils d amelioration :</strong></p><ul>${tips.map((item) => `<li>${item}</li>`).join('')}</ul>`,
      alertSubject: `Alerte de triche - ${item.title}`,
      alertText: `Alerte enseignant:\n\nUne soumission a ete signalee.\n\nEtudiant : ${item.studentName}\nMatiere : ${item.subject}\nDevoir : ${item.title}\nProbabilite IA : ${aiProbability}%\nPourcentage de plagiat : ${plagiarism}%\nAction recommandee : ${analysis.recommended_teacher_action || 'review'}`,
      alertHtml: `<p><strong>Alerte enseignant</strong></p><p>Une soumission a ete signalee.</p><p><strong>Etudiant :</strong> ${item.studentName}<br><strong>Matiere :</strong> ${item.subject}<br><strong>Devoir :</strong> ${item.title}<br><strong>Probabilite IA :</strong> ${aiProbability}%<br><strong>Pourcentage de plagiat :</strong> ${plagiarism}%<br><strong>Action recommandee :</strong> ${analysis.recommended_teacher_action || 'review'}</p>`
    }
  }
];

const report = $input.first().json;
const overview = report.overview || {};
const flaggedRows = Array.isArray(report.flagged_submissions) ? report.flagged_submissions : [];
const flaggedText = flaggedRows.length
  ? flaggedRows.map((row, index) => `${index + 1}. ${row.student_name} - ${row.title} (${row.subject}) | score: ${row.score ?? '-'} | ai: ${row.ai_probability ?? 0}% | plagiarism: ${row.plagiarism_percentage ?? 0}%`).join('\n')
  : 'No flagged homework this week.';
const flaggedHtml = flaggedRows.length
  ? `<ul>${flaggedRows.map((row) => `<li><strong>${row.student_name}</strong> - ${row.title} (${row.subject}) | score: ${row.score ?? '-'} | ai: ${row.ai_probability ?? 0}% | plagiarism: ${row.plagiarism_percentage ?? 0}%</li>`).join('')}</ul>`
  : '<p>No flagged homework this week.</p>';

return [
  {
    json: {
      toEmail: 'teacher@example.com',
      fromEmail: 'teacher@example.com',
      subject: 'Weekly homework summary',
      text: `Weekly Teacher Summary\n\nPeriod: ${report.period || 'Last 7 days'}\nTotal submissions: ${overview.total_submissions ?? 0}\nAverage score: ${overview.average_score ?? 0}\nFlagged homework: ${overview.flagged_homework ?? 0}\nGenerated at: ${report.generated_at || ''}\n\nFlagged list:\n${flaggedText}`,
      html: `<p><strong>Weekly Teacher Summary</strong></p><p><strong>Period:</strong> ${report.period || 'Last 7 days'}<br><strong>Total submissions:</strong> ${overview.total_submissions ?? 0}<br><strong>Average score:</strong> ${overview.average_score ?? 0}<br><strong>Flagged homework:</strong> ${overview.flagged_homework ?? 0}<br><strong>Generated at:</strong> ${report.generated_at || ''}</p><p><strong>Flagged list</strong></p>${flaggedHtml}`
    }
  }
];
